```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_product_sales_report {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* tablename = "ProductSalesReport";
  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    using namespace sqlgen::literals;

    // 1. Create database connection
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // 2. Build the query using sqlgen's fluent interface
    auto query = sqlgen::select_from<Product>(
        "category"_t1,
        sqlgen::sum("quantity"_t2).as<"total_qty">,
        sqlgen::sum("amount"_t2).as<"total_amt">
    )
    | sqlgen::inner_join<Sale>("product_id"_t1 == "product_id"_t2)
    | sqlgen::group_by("category"_t1)
    | sqlgen::where(sqlgen::col<"total_amt">() > 5000.0)
    | sqlgen::to<std::vector<CategoryReport>>;

    // 3. Execute the query and return results
    return query(conn);
}

}  // namespace query_product_sales_report
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Query Construction**: Uses `sqlgen::select_from<Product>` to start building the query
3. **Field Selection**: Selects `category` from Product table and aggregated fields from Sale table
4. **Table Join**: Uses `operator|` with `sqlgen::inner_join` to join Product and Sale tables on `product_id`
5. **Grouping**: Uses `operator|` with `sqlgen::group_by` to group by category
6. **HAVING Condition**: Uses `operator|` with `sqlgen::where` to filter groups where total_amt > 5000
7. **Result Mapping**: Uses `operator|` with `sqlgen::to` to map results to `std::vector<CategoryReport>`

The implementation follows the exact sequence specified in the assessment objectives and leverages all the required sqlgen functions and operators as documented in the reference materials.

