#pragma once

#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

    // Start with base SELECT query
    auto query = sqlgen::read<std::vector<Book>>;

    // Dynamically add WHERE conditions based on non-null filters
    auto condition = true;

    if (filters.title_keyword) {
        condition = condition && ("title"_c.like(*filters.title_keyword));
    }

    if (filters.min_year) {
        condition = condition && ("year"_c >= *filters.min_year);
    }

    if (filters.genre) {
        condition = condition && ("genre"_c == *filters.genre);
    }

    if (filters.max_price) {
        condition = condition && ("price"_c <= *filters.max_price);
    }

    // Apply the condition to the query
    query = query | sqlgen::where(condition);

    // Execute the query and return results
    return query(conn).value();
}

}  // namespace query_search_books_by_criteria
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Base Query**: Starts with `sqlgen::read<std::vector<Book>>` to select all books
3. **Dynamic Conditions**: Builds WHERE clause by combining conditions with `&&` operator
4. **Column References**: Uses string literals with `_c` suffix (`"title"_c`, `"year"_c`, etc.)
5. **Condition Types**:
   - `like()` for title pattern matching
   - Comparison operators (`>=`, `==`, `<=`) for numeric comparisons
6. **Query Execution**: Applies conditions using `| sqlgen::where()` and executes with `query(conn)`

The implementation follows sqlgen's fluent API pattern and properly handles optional filters by only including conditions when their corresponding filter values are non-null.

