```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");

  // Chain operations using fluent API with operator|
  return conn_result
      // Start transaction
      .and_then(sqlgen::begin_transaction)
      // Read sender account to check balance
      .and_then([&](const auto& conn) {
          return (sqlgen::read<Account> | sqlgen::where("account_id"_c == from_account_id))(conn);
      })
      .and_then([&](Account sender) -> rfl::Result<sqlgen::Ref<sqlgen::sqlite::Connection>> {
          // Check if sender has sufficient balance
          if (sender.balance < amount) {
              return sqlgen::rollback(conn).transform([](auto&&) { return conn; });
          }

          // Update sender's balance (balance = balance - amount)
          auto update_sender = sqlgen::update<Account>("balance"_c.set("balance - ?"));
          return (update_sender | sqlgen::where("account_id"_c == from_account_id))(conn)
              .and_then([&](const auto& updated_conn) {
                  // Update receiver's balance (balance = balance + amount)
                  auto update_receiver = sqlgen::update<Account>("balance"_c.set("balance + ?"));
                  return (update_receiver | sqlgen::where("account_id"_c == to_account_id))(updated_conn);
              });
      })
      .and_then(sqlgen::commit)
      .transform([](auto&&) { return true; })
      .or_else([&](const auto& error) {
          // Rollback on any failure
          sqlgen::rollback(conn);
          return rfl::error(error);
      })
      .value_or(false);
}

}  // namespace transaction_transfer_funds
