```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::string city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    using namespace sqlgen::literals;

    // Create database connection
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Create tables
    conn.execute(R"(
        CREATE TABLE User (
            user_id INTEGER PRIMARY KEY,
            username VARCHAR(50) NOT NULL UNIQUE,
            email VARCHAR(100) NOT NULL UNIQUE,
            join_date DATETIME NOT NULL,
            city VARCHAR(50)
        )
    )");

    conn.execute(R"(
        CREATE TABLE Friendship (
            user_id1 INTEGER REFERENCES User(user_id),
            user_id2 INTEGER REFERENCES User(user_id),
            friendship_date DATETIME NOT NULL,
            PRIMARY KEY (user_id1, user_id2)
        )
    )");

    // Insert data
    sqlgen::write(conn, users);
    sqlgen::write(conn, friendships);

    // Query 1: Mutual friends using SELF-JOIN
    auto mutual_friends_query = sqlgen::read<std::vector<FriendConnection>>
        | sqlgen::select_from<User, "u1">("username"_t1 | sqlgen::as<"user1_name">, 
                                         "username"_t2 | sqlgen::as<"user2_name">)
        | sqlgen::inner_join<Friendship, "f1">("u1"_t1.user_id == "f1"_t3.user_id1)
        | sqlgen::inner_join<User, "u2">("f1"_t3.user_id2 == "u2"_t2.user_id)
        | sqlgen::where("u1"_t1.user_id < "u2"_t2.user_id)
        | sqlgen::group_by("u1"_t1.user_id, "u2"_t2.user_id)
        | sqlgen::having(sqlgen::count() > 0);

    // Query 2: Users with more than average friends using nested query
    auto avg_friends_subquery = sqlgen::read<std::vector<int>> 
        | sqlgen::select_from<Friendship>("user_id1"_t1)
        | sqlgen::group_by("user_id1"_t1)
        | sqlgen::to<std::vector<int>>;

    auto high_friend_count_query = sqlgen::read<std::vector<FriendConnection>>
        | sqlgen::select_from<User>("username"_t1 | sqlgen::as<"user1_name">, 
                                   "username"_t2 | sqlgen::as<"user2_name">)
        | sqlgen::left_join<Friendship>("user_id"_t1 == "user_id1"_t2)
        | sqlgen::where(sqlgen::count("user_id2"_t2) > 
                       (sqlgen::avg(sqlgen::count("user_id2"_t2)) | sqlgen::from(avg_friends_subquery)))
        | sqlgen::order_by(sqlgen::count("user_id2"_t2).desc());

    // Query 3: Friend-of-friend relationships
    auto friend_of_friend_query = sqlgen::read<std::vector<FriendConnection>>
        | sqlgen::select_from<User, "u1">("username"_t1 | sqlgen::as<"user1_name">, 
                                         "username"_t2 | sqlgen::as<"user2_name">)
        | sqlgen::inner_join<Friendship, "f1">("u1"_t1.user_id == "f1"_t3.user_id1)
        | sqlgen::inner_join<Friendship, "f2">("f1"_t3.user_id2 == "f2"_t4.user_id1)
        | sqlgen::inner_join<User, "u2">("f2"_t4.user_id2 == "u2"_t2.user_id)
        | sqlgen::where("u1"_t1.user_id < "u2"_t2.user_id)
        | sqlgen::having(sqlgen::count("f1"_t3.user_id2) == 1);

    // Query 4: Count friends per user and identify most connected users
    auto friend_stats_query = sqlgen::read<std::vector<FriendConnection>>
        | sqlgen::select_from<User>("username"_t1 | sqlgen::as<"user1_name">, 
                                   sqlgen::count("user_id2"_t2) | sqlgen::as<"friend_count">)
        | sqlgen::left_join<Friendship>("user_id"_t1 == "user_id1"_t2)
        | sqlgen::group_by("user_id"_t1)
        | sqlgen::order_by("friend_count"_t1.desc());

    // Query 5: Users in same city not yet friends (recommendations)
    auto recommendation_query = sqlgen::read<std::vector<FriendConnection>>
        | sqlgen::select_from<User, "u1">("username"_t1 | sqlgen::as<"user1_name">, 
                                         "username"_t2 | sqlgen::as<"user2_name">)
        | sqlgen::inner_join<User, "u2">("u1"_t1.city == "u2"_t2.city)
        | sqlgen::where("u1"_t1.user_id < "u2"_t2.user_id)
        | sqlgen::and_where(sqlgen::not_exists(
            sqlgen::select_from<Friendship>("user_id1"_t3)
            | sqlgen::where(("user_id1"_t3 == "u1"_t1.user_id) && 
                           ("user_id2"_t3 == "u2"_t2.user_id))
        ));

    // Execute all queries and return combined results
    auto mutual_results = mutual_friends_query(conn);
    auto friend_of_friend_results = friend_of_friend_query(conn);
    auto recommendation_results = recommendation_query(conn);

    std::vector<FriendConnection> all_results;
    all_results.reserve(mutual_results.size() + friend_of_friend_results.size() + recommendation_results.size());

    all_results.insert(all_results.end(), mutual_results.begin(), mutual_results.end());
    all_results.insert(all_results.end(), friend_of_friend_results.begin(), friend_of_friend_results.end());
    all_results.insert(all_results.end(), recommendation_results.begin(), recommendation_results.end());

    return all_results;
}

}  // namespace analyze_social_network
```

This implementation:

1. **Creates the required tables** with proper schema definitions
2. **Uses SELF-JOIN** for mutual friends detection by joining User table with itself through Friendship table
3. **Uses nested queries** for finding users with above-average friend counts
4. **Identifies friend-of-friend relationships** with exact one mutual friend constraint
5. **Aggregates statistics** using count() and avg() functions
6. **Finds recommendation opportunities** using NOT EXISTS with subquery
7. **Returns results** as `std::vector<FriendConnection>` as specified

The code follows sqlgen library patterns from the reference materials, using the fluent API with operator| for query building, proper table aliases, column references, and aggregation functions.

