bool cascade_delete_demo() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // 2. Drop tables if they exist to ensure clean state
  auto drop_parent = drop<Parent> | if_exists;
  auto drop_child = drop<Child> | if_exists;

  auto drop_result1 = drop_parent(conn);
  auto drop_result2 = drop_child(conn);
  if (!drop_result1 || !drop_result2) {
    return false;
  }

  // 3. Create tables
  auto create_parent = create_table<Parent>;
  auto create_child = create_table<Child>;

  auto create_result1 = create_parent(conn);
  auto create_result2 = create_child(conn);
  if (!create_result1 || !create_result2) {
    return false;
  }

  // 4. Insert parent and child records
  Parent parent{1, "Parent Record"};
  Child child{1, 1, "Child Record"};

  auto insert_parent = insert(parent);
  auto insert_child = insert(child);

  auto insert_result1 = insert_parent(conn);
  auto insert_result2 = insert_child(conn);
  if (!insert_result1 || !insert_result2) {
    return false;
  }

  // 5. Delete parent record
  auto delete_parent = delete_from<Parent> | where("parent_id"_c == 1);
  auto delete_result = delete_parent(conn);
  if (!delete_result) {
    return false;
  }

  // 6. Verify child deletion
  auto verify_child = read<std::vector<Child>> | where("child_id"_c == 1);
  auto child_result = verify_child(conn);

  // 7. Return verification result
  return !child_result || child_result->empty();
}

