```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // 1. Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Read Sales data from the database
  auto sales_data = sqlgen::read<std::vector<Sales>> | conn;

  // 3. Extract weekday from sale_time and group by weekday, summing quantities
  auto result = (sqlgen::read<std::vector<Sales>> 
                | sqlgen::group_by(sqlgen::extract<"weekday">(sqlgen::col<"sale_time">))
                | sqlgen::sum(sqlgen::col<"quantity">))
                | sqlgen::to<std::vector<WeekdayStats>>;

  // 4. Execute the query and return results
  return result(conn).value();
}

}  // namespace weekday_sales_analysis
```

